const articles  = $('Get this week\'s articles').all().map(i => i.json);
const upcoming  = $('Get upcoming events').all().map(i => i.json);
const pastEvts  = $('Get past week events').all().map(i => i.json);
const weekStart = new Date(); weekStart.setDate(weekStart.getDate() - 7);
const recentArticles = articles.filter(a => new Date(a.published_at) >= weekStart);

// Group articles by category for hot topics detection
const catCount = {};
recentArticles.forEach(a => { catCount[a.category] = (catCount[a.category]||0)+1; });
const hotTopics = Object.entries(catCount).sort((a,b)=>b[1]-a[1]).slice(0,3).map(([cat,n])=>cat);

// Format article list for Claude
const articleLines = recentArticles.slice(0,10).map((a,i) =>
  `${i+1}. [${a.category.toUpperCase()}${a.region!=='all'?' · '+a.region:''}] ${a.title} — ${a.source_url}`
).join('\n');

// Format upcoming events
const upcomingLines = upcoming.filter(e => new Date(e.event_date) >= new Date()).slice(0,6).map(e =>
  `• ${e.event_date} — ${e.title}, ${e.city} (${e.category})`
).join('\n');

// Format past events
const pastLines = pastEvts.filter(e => new Date(e.event_date) < new Date() && new Date(e.event_date) >= weekStart).slice(0,4).map(e =>
  `• ${e.event_date} — ${e.title}, ${e.city}`
).join('\n');

const weekLabel = new Date().toLocaleDateString('en-GB', { day:'numeric', month:'long', year:'numeric' });

return [{ json: { articleLines, upcomingLines, pastLines, hotTopics: hotTopics.join(', '), weekLabel, articleCount: recentArticles.length } }];

